#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        while (Q--) {
            int a, b, c, d;
            scanf("%d %d %d %d", &a, &b, &c, &d);
            a--; b--; c--; d--;
            int len = b - a + 1;
            int sub1[len], sub2[len];
            for (int i = 0; i < len; i++) {
                sub1[i] = A[a + i];
                sub2[i] = A[c + i];
            }
            qsort(sub1, len, sizeof(int), compare);
            qsort(sub2, len, sizeof(int), compare);
            int mismatch = 0;
            for (int i = 0; i < len; i++) {
                if (sub1[i] != sub2[i]) {
                    mismatch++;
                }
            }
            if (mismatch <= 1) {
                printf("YES\n");
            } else {
                printf("NO\n");
            }
        }
    }
    return 0;
}

