import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int Q = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            while (Q-- > 0) {
                int a = sc.nextInt();
                int b = sc.nextInt();
                int c = sc.nextInt();
                int d = sc.nextInt();
                a--; b--; c--; d--;
                int len = b - a + 1;
                int[] sub1 = new int[len];
                int[] sub2 = new int[len];
                for (int i = 0; i < len; i++) {
                    sub1[i] = A[a + i];
                    sub2[i] = A[c + i];
                }
                Arrays.sort(sub1);
                Arrays.sort(sub2);
                int mismatch = 0;
                for (int i = 0; i < len; i++) {
                    if (sub1[i] != sub2[i]) {
                        mismatch++;
                    }
                }
                if (mismatch <= 1) {
                    System.out.println("YES");
                } else {
                    System.out.println("NO");
                }
            }
        }
    }
}

