const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextInt() {
    return parseInt(input[idx++]);
}

function nextIntArray() {
    return input[idx++].split(' ').map(x => parseInt(x));
}

let T = nextInt();
while (T-- > 0) {
    let [N, Q] = nextIntArray();
    let A = nextIntArray();
    while (Q-- > 0) {
        let [a, b, c, d] = nextIntArray();
        a--; b--; c--; d--;
        let len = b - a + 1;
        let sub1 = A.slice(a, b + 1).sort((x, y) => x - y);
        let sub2 = A.slice(c, d + 1).sort((x, y) => x - y);
        let mismatch = 0;
        for (let i = 0; i < len; i++) {
            if (sub1[i] !== sub2[i]) {
                mismatch++;
            }
        }
        if (mismatch <= 1) {
            console.log('YES');
        } else {
            console.log('NO');
        }
    }
}

